def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    n = len(bins)
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            continue
        if item > capacity:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio == 1:
            score = 0.0
        elif ratio > 0.9:
            score = (1 - ratio) ** 4 + 0.15
        elif 0.7 < ratio <= 0.9:
            score = np.exp(-12 * ratio) + 0.12
        elif 0.3 < ratio <= 0.7:
            score = (0.3 - ratio) ** 2 + 0.08
        else:
            s1 = 0.0
            for k in range(1, 8):
                s1 += ((-1) ** k) * (ratio ** (k+2)) / (k * 1.2)
            s2 = 0.0
            for m in range(5):
                s2 += (ratio ** (2 * m + 1)) / ((m + 1) * 3)
            score = abs(s1) + abs(s2) + 0.04
        neighbors_influence = 0.0
        for offset in range(1, 7):
            neighbors = []
            if i - offset >= 0:
                neighbors.append(bins[i - offset])
            if i + offset < n:
                neighbors.append(bins[i + offset])
            for neighbor_capacity in neighbors:
                if neighbor_capacity > 0:
                    diff_ratio = abs(capacity - neighbor_capacity) / max(capacity, neighbor_capacity)
                    weight = 1 / (offset ** 1.5)
                    neighbors_influence += diff_ratio * weight * 0.1
        capacity_factor = np.sqrt(capacity)
        if capacity_factor == 0:
            capacity_factor = 1
        adjustment = 0.0
        for j in range(n):
            if j == i:
                continue
            dist = abs(i - j)
            if dist <= 3:
                cap_j = bins[j]
                if cap_j > 0:
                    adj_val = ((capacity - cap_j) / max(capacity, cap_j)) * np.exp(-dist)
                    adjustment += adj_val * 0.05
        priority = score + neighbors_influence / capacity_factor + adjustment
        if priority < 0:
            priority = 0
        if priority > 1:
            priority = 1 - (1 / (priority + 1))
        priorities[i] = priority
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_finite = np.max(finite_priorities)
    for i in range(n):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_finite * 7
    for _ in range(2):
        for i in range(n):
            if priorities[i] == max_finite * 7:
                left = priorities[i-1] if i - 1 >= 0 else max_finite
                right = priorities[i+1] if i + 1 < n else max_finite
                priorities[i] = (left + right) / 2
    return priorities
